+	sp->count = 0;
+	pthread_mutex_init(&sp->mutex, NULL);
+	pthread_cond_init(&sp->not_empty, NULL);
+	pthread_cond_init(&sp->not_full, NULL);
+}
+
+/*
+ * Requires:
+ *   sp points to an initialized sbuf_t.
+ *
+ * Effects:
+ *   Inserts item into the buffer, blocking until a slot is available.
+ */
+static void
+sbuf_insert(sbuf_t *sp, int item)
+{
+	pthread_mutex_lock(&sp->mutex);
+	while (sp->count == sp->n)
+		pthread_cond_wait(&sp->not_full, &sp->mutex);
+	sp->buf[sp->rear] = item;
+	sp->rear = (sp->rear + 1) % sp->n;
+	sp->count++;
+	pthread_cond_signal(&sp->not_empty);
+	pthread_mutex_unlock(&sp->mutex);
+}
+
+/*
+ * Requires:
+ *   sp points to an initialized sbuf_t.
+ *
+ * Effects:
+ *   Removes and returns the front item from the buffer, blocking until
+ *   an item is available.
+ */
+static int
+sbuf_remove(sbuf_t *sp)
+{
+	int item;
+
+	pthread_mutex_lock(&sp->mutex);
+	while (sp->count == 0)
+		pthread_cond_wait(&sp->not_empty, &sp->mutex);
+	item = sp->buf[sp->front];
+	sp->front = (sp->front + 1) % sp->n;
+	sp->count--;
+	pthread_cond_signal(&sp->not_full);
+	pthread_mutex_unlock(&sp->mutex);
+	return (item);
+}
+
+/*
+ * Requires:
+ *   hostname and port point to valid NUL-terminated strings.
+ *
+ * Effects:
+ *   Opens a client connection to hostname:port. Returns the file descriptor
+ *   on success, or -1 on failure. Thread-safe; properly handles DNS failure.
+ */
+static int
+open_clientfd_ts(const char *hostname, const char *port)
+{
+	int clientfd, rc;
+	struct addrinfo hints, *listp, *p;
+
+	memset(&hints, 0, sizeof(struct addrinfo));
+	hints.ai_socktype = SOCK_STREAM;
+	hints.ai_flags = AI_NUMERICSERV | AI_ADDRCONFIG;
+
+	rc = getaddrinfo(hostname, port, &hints, &listp);
+	if (rc != 0)
+		return (-1);
+
+	for (p = listp; p != NULL; p = p->ai_next) {
+		clientfd = socket(p->ai_family, p->ai_socktype,
+		    p->ai_protocol);
+		if (clientfd < 0)
+			continue;
+		if (connect(clientfd, p->ai_addr, p->ai_addrlen) != -1)
+			break;
+		close(clientfd);
+	}
+
+	freeaddrinfo(listp);
+	if (p == NULL)
+		return (-1);
+	return (clientfd);
+}
+
+/*
+ * Requires:
+ *   rp points to an initialized rio_t.
+ *
+ * Effects:
+ *   Reads a complete line (ending in '\n') from rp, dynamically expanding
+ *   the buffer to handle lines longer than MAXLINE. Returns a dynamically
+ *   allocated NUL-terminated string, or NULL on error/EOF. Caller must free.
+ */
+static char *
+read_requestline(rio_t *rp)
+{
+	size_t bufsize, total;
+	ssize_t n;
+	char *buf, *newbuf;
+
+	bufsize = MAXLINE;
+	total = 0;
+	buf = malloc(bufsize);
+	if (buf == NULL)
+		return (NULL);
+
+	while (1) {
+		n = rio_readlineb(rp, buf + total, bufsize - total);
+		if (n <= 0) {
+			free(buf);
+			return (NULL);
+		}
+		total += n;
+		/* Check if we got a complete line (ends with '\n'). */
+		if (buf[total - 1] == '\n')
+			break;
+		/* Line isn't complete; expand the buffer. */
+		bufsize *= 2;
+		newbuf = realloc(buf, bufsize);
+		if (newbuf == NULL) {
+			free(buf);
+			return (NULL);
+		}
+		buf = newbuf;
+	}
+	return (buf);
+}
+
+/*
+ * Requires:
+ *   connfd is a valid, open socket connected to a client.
+ *
+ * Effects:
+ *   Handles a single HTTP GET request. Reads the request from the client,
+ *   connects to the end server, forwards the request (rewriting the first
+ *   line and filtering persistent-connection headers), forwards the
+ *   response back, and logs the completed transaction.
+ */
+static void
+handle_request(int connfd)
+{
+	rio_t client_rio;
+	struct sockaddr_in clientaddr;
+	socklen_t clientlen;
+	char *reqline, *uri, *hostname, *port, *pathname;
+	char *saveptr, *tok_method, *tok_uri;
+	char method[16], hdrbuf[MAXBUF], line[MAXLINE], reqbuf[MAXLINE];
+	char buf[MAXBUF];
+	int hdrlen, has_host, serverfd, total_size, reqlen, llen;
+	ssize_t n;
+
+	uri = NULL;
+	hostname = NULL;
+	port = NULL;
+	pathname = NULL;
+	serverfd = -1;
+
+	/* Get the client's address for logging. */
+	clientlen = sizeof(clientaddr);
+	if (getpeername(connfd, (SA *)&clientaddr, &clientlen) < 0)
+		return;
+
+	/* Initialize RIO for reading from the client. */
+	rio_readinitb(&client_rio, connfd);
+
+	/* Read the request line (handles URIs longer than MAXLINE). */
+	reqline = read_requestline(&client_rio);
+	if (reqline == NULL)
+		return;
+
+	/* Parse method and URI from the request line. */
+	tok_method = strtok_r(reqline, " \t", &saveptr);
+	tok_uri = strtok_r(NULL, " \t\r\n", &saveptr);
+	if (tok_method == NULL || tok_uri == NULL) {
+		client_error(connfd, "", 400, "Bad Request",
+		    "Malformed request line");
+		free(reqline);
+		return;
+	}
+
+	/* Save method and URI before freeing the request line buffer. */
+	strncpy(method, tok_method, sizeof(method) - 1);
+	method[sizeof(method) - 1] = '\0';
+	uri = strdup(tok_uri);
+	free(reqline);
+	if (uri == NULL)
+		return;
+
+	/* Only support the GET method. */
+	if (strcasecmp(method, "GET") != 0) {
+		client_error(connfd, method, 501, "Not Implemented",
+		    "Proxy does not support this method");
+		free(uri);
+		return;
+	}
+
+	/* Parse the URI into hostname, port, pathname. */
+	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
+		client_error(connfd, uri, 400, "Bad Request",
+		    "Could not parse the URI");
+		free(uri);
+		return;
+	}
+
+	/* Read and filter request headers from the client. */
+	hdrlen = 0;
+	has_host = 0;
+	while ((n = rio_readlineb(&client_rio, line, sizeof(line))) > 0) {
+		/* An empty line signals the end of the headers. */
+		if (strcmp(line, "\r\n") == 0 || strcmp(line, "\n") == 0)
+			break;
+		/* Strip persistent-connection headers. */
+		if (strncasecmp(line, "Connection:", 11) == 0 ||
+		    strncasecmp(line, "Keep-Alive:", 11) == 0 ||
+		    strncasecmp(line, "Proxy-Connection:", 17) == 0)
+			continue;
+		if (strncasecmp(line, "Host:", 5) == 0)
+			has_host = 1;
+		/* Append header to buffer if there is room. */
+		llen = (int)strlen(line);
+		if (hdrlen + llen < (int)sizeof(hdrbuf)) {
+			memcpy(hdrbuf + hdrlen, line, llen);
+			hdrlen += llen;
+		}
+	}
+
+	/* Connect to the end server. */
+	serverfd = open_clientfd_ts(hostname, port);
+	if (serverfd < 0) {
+		client_error(connfd, hostname, 502, "Bad Gateway",
+		    "Could not connect to the end server");
+		goto cleanup;
+	}
+
+	/* Send the modified request line to the server. */
+	reqlen = snprintf(reqbuf, sizeof(reqbuf),
+	    "GET %s HTTP/1.0\r\n", pathname);
+	if (rio_writen(serverfd, reqbuf, reqlen) < 0)
+		goto cleanup;
+
+	/* Add a Host header if the client did not provide one. */
+	if (!has_host) {
+		reqlen = snprintf(reqbuf, sizeof(reqbuf),
+		    "Host: %s\r\n", hostname);
+		if (rio_writen(serverfd, reqbuf, reqlen) < 0)
+			goto cleanup;
+	}
+
+	/* Add a Connection: close header. */
+	if (rio_writen(serverfd, "Connection: close\r\n", 19) < 0)
+		goto cleanup;
+
+	/* Forward the remaining request headers. */
+	if (hdrlen > 0 && rio_writen(serverfd, hdrbuf, hdrlen) < 0)
+		goto cleanup;
+
+	/* Send the empty line to end the request headers. */
+	if (rio_writen(serverfd, "\r\n", 2) < 0)
+		goto cleanup;
+
+	/* Forward the response from the server to the client. */
+	total_size = 0;
+	while ((n = rio_readn(serverfd, buf, sizeof(buf))) > 0) {
+		total_size += n;
+		if (rio_writen(connfd, buf, n) < 0)
+			break;
+	}
+
+	/* Log the completed transaction if any data was received. */
+	if (total_size > 0) {
+		char *log_entry = create_log_entry(&clientaddr, uri,
+		    total_size);
+		pthread_mutex_lock(&log_mutex);
+		fprintf(log_file, "%s\n", log_entry);
+		fflush(log_file);
+		pthread_mutex_unlock(&log_mutex);
+		free(log_entry);
+	}
+
+cleanup:
+	if (serverfd >= 0)
+		close(serverfd);
+	free(hostname);
+	free(port);
+	free(pathname);
+	free(uri);
+}
+
+/*
+ * Requires:
+ *   vargp is unused.
+ *
+ * Effects:
+ *   Worker thread routine. Detaches itself, then continuously removes
+ *   connection descriptors from the shared buffer, handles the request,
+ *   and closes the connection.
+ */
+static void *
+thread_routine(void *vargp)
+{
+	int connfd;
+
+	(void)vargp;
+	Pthread_detach(Pthread_self());
+	while (1) {
+		connfd = sbuf_remove(&sbuf);
+		handle_request(connfd);
+		close(connfd);
+	}
+	return (NULL);
+}
